#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <limits.h>

#define N 200010

typedef struct {
    int to, weight;
} Edge;

typedef struct {
    Edge *edges;
    int size, capacity;
} AdjList;

bool *vis;
AdjList *adj;

// Priority queue structure for edges
typedef struct {
    int weight, vertex;
} PQNode;

typedef struct {
    PQNode *nodes;
    int size, capacity;
} PriorityQueue;

void pq_init(PriorityQueue *pq, int capacity) {
    pq->nodes = (PQNode *)malloc(capacity * sizeof(PQNode));
    pq->size = 0;
    pq->capacity = capacity;
}

void pq_push(PriorityQueue *pq, int weight, int vertex) {
    if (pq->size == pq->capacity) {
        pq->capacity *= 2;
        pq->nodes = (PQNode *)realloc(pq->nodes, pq->capacity * sizeof(PQNode));
    }
    int i = pq->size++;
    while (i > 0) {
        int p = (i - 1) / 2;
        if (pq->nodes[p].weight <= weight) break;
        pq->nodes[i] = pq->nodes[p];
        i = p;
    }
    pq->nodes[i].weight = weight;
    pq->nodes[i].vertex = vertex;
}

PQNode pq_pop(PriorityQueue *pq) {
    PQNode ret = pq->nodes[0];
    PQNode tmp = pq->nodes[--pq->size];
    int i = 0;
    while (i * 2 + 1 < pq->size) {
        int left = i * 2 + 1, right = i * 2 + 2;
        int j = left;
        if (right < pq->size && pq->nodes[right].weight < pq->nodes[left].weight) {
            j = right;
        }
        if (pq->nodes[j].weight >= tmp.weight) break;
        pq->nodes[i] = pq->nodes[j];
        i = j;
    }
    pq->nodes[i] = tmp;
    return ret;
}

void adjlist_init(AdjList *list) {
    list->edges = (Edge *)malloc(4 * sizeof(Edge));
    list->size = 0;
    list->capacity = 4;
}

void adjlist_add(AdjList *list, int to, int weight) {
    if (list->size == list->capacity) {
        list->capacity *= 2;
        list->edges = (Edge *)realloc(list->edges, list->capacity * sizeof(Edge));
    }
    list->edges[list->size].to = to;
    list->edges[list->size].weight = weight;
    list->size++;
}

void prims(int source, int n) { // Source is the starting vertex
    long long ans = 0;  // Total weight of the MST
    PriorityQueue pq;
    pq_init(&pq, n);

    pq_push(&pq, 0, source);

    while (pq.size > 0) {
        PQNode node = pq_pop(&pq);
        int v = node.vertex;

        if (vis[v]) {
            continue;
        }

        ans += node.weight;  // Add the edge weight to answer
        vis[v] = true;  // Mark vertex as processed

        for (int i = 0; i < adj[v].size; i++) {
            Edge edge = adj[v].edges[i];
            if (!vis[edge.to]) {
                pq_push(&pq, edge.weight, edge.to);
            }
        }
    }

    printf("%lld\n", ans);

    free(pq.nodes);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        // Allocate memory for vis array and adjacency list
        vis = (bool *)malloc((n + 1) * sizeof(bool));
        adj = (AdjList *)malloc((n + 1) * sizeof(AdjList));

        // Initialize vis array and adjacency list
        for (int i = 1; i <= n; i++) {
            vis[i] = false;
            adjlist_init(&adj[i]);
        }

        // Read edges
        for (int i = 0; i < m; i++) {
            int x, y, w;
            scanf("%d %d %d", &x, &y, &w);
            adjlist_add(&adj[x], y, w);
            adjlist_add(&adj[y], x, w);
        }

        prims(1, n);

        // Free allocated memory
        free(vis);
        for (int i = 1; i <= n; i++) {
            free(adj[i].edges);
        }
        free(adj);
    }

    return 0;
}

