    long long ans = 0; // Total weight of the MST

    priority_queue<vector<int>, vector<vector<int>>, greater<vector<int>>> pq;

    pq.push({0, source}); 

    while(pq.size() != 0) {
        vector<int> node = pq.top();
        pq.pop();

        int v = node[1];

        if(vis[v]){
            continue;
        }

        ans += node[0]; // Add the edge weight to answer

        vis[v] = 1; // Mark vertex as processed

        for(auto edge: adj[v]) {
            if(!vis[edge.first]){
                pq.push({edge.second, edge.first});   
            }
        }
    }      

    cout << ans << "\n"; 
