function readline() {
    return lines[idx++];
}

function prims(n, m, edges) {
    let ans = 0;
    let vis = new Array(n + 1).fill(false);
    let adj = new Array(n + 1).fill(0).map(() => []);

    for (let i = 0; i < m; i++) {
        let [u, v, w] = edges[i];
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    let pq = [[0, 1]];

    while (pq.length > 0) {
        pq.sort((a, b) => a[0] - b[0]);
        let [weight, v] = pq.shift();

        if (vis[v]) {
            continue;
        }

        ans += weight;
        vis[v] = true;

        for (let [u, w] of adj[v]) {
            if (!vis[u]) {
                pq.push([w, u]);
            }
        }
    }

    return ans;
}

